#!/usr/bin/env bash
# workflow-4.sh — 单次面试的结构（准备 / 临场 / 复盘） SOP walkthrough for 求职 / 面试辅导(求职教练视角 — 求职定位与职业叙事 / 简历与 ATS 优化 / 求职渠道与内推策略 / 职场社交 / 行为面试与专业面试 / 面试心理与表达 / 谈薪与 offer 决策 / 校招与应届生 / 转行求职 / 特殊群体求职 / 求职教练的执业经营 — 涵盖中国大陆求职生态 + 海外英语区求职体系,两套差异极大).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="求职 / 面试辅导(求职教练视角 — 求职定位与职业叙事 / 简历与 ATS 优化 / 求职渠道与内推策略 / 职场社交 / 行为面试与专业面试 / 面试心理与表达 / 谈薪与 offer 决策 / 校招与应届生 / 转行求职 / 特殊群体求职 / 求职教练的执业经营 — 涵盖中国大陆求职生态 + 海外英语区求职体系,两套差异极大)"
WORKFLOW="单次面试的结构（准备 / 临场 / 复盘）"

usage() {
  cat <<EOF
workflow-4.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-4.sh             # interactive
  ./workflow-4.sh --dry-run
  ./workflow-4.sh --json
  ./workflow-4.sh --explain
  ./workflow-4.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "单次面试的结构（准备 / 临场 / 复盘）" 工作流。

一句话: 把一场具体面试从「拿到邀约」到「完成 + 复盘」走成一个可重复的闭环 —— 不是临场发挥，是「准备 → 临场 → 复盘」三段式，复盘喂回下一场。

入门 SOP 共 5 步, 失败模式自检 5 项。

相关心智模型:
  • 定位先于一切执行（定位错了，后面是高效地做错事）: 求职的第一性问题不是「简历怎么写 / 该投哪」，而是「要找哪一类岗位 + 为什么是我」—— 目标不收敛时，改简历、海投、练面试都是在高效地做错的事。
  • 从招聘方 / ATS / 岗位的痛点出发倒推（不是从「我想要什么」出发）: 简历、触达、面试答案的组织原点是「这个岗位 / 招聘经理在解决什么问题」，不是「我想说什么」—— 招聘经理立项前往往已缺人 6-12 个月，他要的是「缓解」。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**公司 + 岗位研究**：研究公司业务 / 近期动态、JD 关注点、面经（Glassdoor / 牛客 / 一亩三分地），判断这一轮考什么。**跳过会发生什么**：对公司一无所知 → 答「为什么是我们」时空洞、反向提问问不出有质量的问题，减分。"
  "**按面试类型准备内容**：行为面准备 STAR 故事（每段经历有可量化 Result）；专业面按岗位类型准备（技术岗刷高频题 / 系统设计、咨询 case、PM 产品题）。**跳过会发生什么**：行为面讲成流水账 / 职责描述、专业面没框架，被「讲不清楚」刷掉。"
  "**临场：结构化作答 + 双向评估**：把每个回答讲出结构（行为题套 STAR；技术题先澄清问题→举例→暴力解→优化→写→测）；同时记住面试是双向的，自己也在筛雇主，结尾做有质量的反向提问。**跳过会发生什么**：答案无结构（面试官跟不上）/ 不反向提问（显得不在意 + 错过筛雇主的机会）。"
  "**跟进**：面试后发一封简短得体的感谢 / 跟进邮件（海外更常见，国内视场景）。**跳过会发生什么**：在「礼仪重要 + 候选人接近」的场景下，少这一步可能微弱失分（但反复追问进度反而是负面 —— 跟进 ≠ 催）。"
  "**复盘**：趁记忆新，结构化记录 —— 哪些问题答得好 / 哪些卡住 / 面试官的反应 / 下一场要改什么。**跳过会发生什么**：只「面」不「复盘」→ 同样的错误下一场再犯，面试经验不累积。"
)
declare -a FAILURE_MODES=(
  "**逐字背稿，被追问就崩**：触发原因 = 把面试当「背诵考试」；后果 = 临场追问 / 变体问题接不住，且背诵痕迹本身减分（显得不真诚）。怎么避免：准备「要点 + 故事素材」，不准备逐字稿；用 mock 练「被追问时还能讲清楚」。"
  "**只「面」不「复盘」**：触发原因 = 面完就想休息 / 等结果；后果 = 经验不累积，同样的错误反复犯。怎么避免：面后趁记忆新做结构化复盘，喂回下一场。"
  "**行为面讲成流水账 / 职责描述**：触发原因 = 不知道行为面要的是「证据」不是「经历叙述」；后果 = 答得再流畅也没有可评分的实质。怎么避免：套 STAR，每段经历必须有可衡量的 Result。"
  "**把面试神秘化（读微表情 / 靠气场 / 话术征服）**：触发原因 = 营销话术 + 不懂结构化面试机制；后果 = 准备方向错，把精力花在表演术上。怎么避免：理解结构化面试按 rubric 评分，准备方向是「对着能力锚点准备真实证据」。"
  "**被一场失败带崩**：触发原因 = 把单场结果等同于自我评价；后果 = 心态崩、影响后续面试。怎么避免：教练做情绪复盘，单场结果和自我评价解耦 —— 一场面试是一次匹配，不是一次审判。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-4-walkthrough"
fi
